def compute_model_placement(gpu_num, models):
    """
    Compute a model placement that minimizes the maximum KVPR across all GPUs.
    Uses look-ahead greedy with multiple orderings + local search (moves & swaps).
    """

    def calc_kvpr(wrr, mem_remaining):
        if mem_remaining <= 0:
            return float('inf')
        return wrr / mem_remaining

    def get_max_kvpr(wrr_list, mem_list):
        max_k = 0.0
        for i in range(len(wrr_list)):
            if mem_list[i] < GPU_MEM_SIZE:  # only count GPUs with models
                k = calc_kvpr(wrr_list[i], mem_list[i])
                if k > max_k:
                    max_k = k
        return max_k

    def lookahead_greedy(sorted_models, gpu_num):
        placement = {gpu_id: [] for gpu_id in range(gpu_num)}
        mem = [GPU_MEM_SIZE] * gpu_num
        wrr = [0.0] * gpu_num

        for model in sorted_models:
            model_wrr = model.req_rate / model.slo
            best_idx = None
            best_resulting_kvpr = float('inf')

            for gpu_id in range(gpu_num):
                new_mem = mem[gpu_id] - model.model_size
                if new_mem <= 0:
                    continue
                resulting_kvpr = (wrr[gpu_id] + model_wrr) / new_mem
                if resulting_kvpr < best_resulting_kvpr:
                    best_resulting_kvpr = resulting_kvpr
                    best_idx = gpu_id

            if best_idx is None:
                # Fallback: try to find any GPU with enough space
                for gpu_id in range(gpu_num):
                    if mem[gpu_id] >= model.model_size and mem[gpu_id] - model.model_size > 0:
                        best_idx = gpu_id
                        break
                if best_idx is None:
                    raise ValueError(
                        f"Unable to place model of size {model.model_size} GB on any GPU."
                    )

            placement[best_idx].append(model)
            wrr[best_idx] += model_wrr
            mem[best_idx] -= model.model_size

        return placement, wrr, mem

    def local_search(placement, wrr, mem, gpu_num, max_iters=200):
        improved = True
        iters = 0
        while improved and iters < max_iters:
            improved = False
            iters += 1

            # Find the GPU with max KVPR
            max_kvpr = -1.0
            max_gpu = -1
            for g in range(gpu_num):
                if mem[g] < GPU_MEM_SIZE:
                    k = calc_kvpr(wrr[g], mem[g])
                    if k > max_kvpr:
                        max_kvpr = k
                        max_gpu = g

            if max_gpu == -1:
                break

            # Try moving models from max_gpu to other GPUs
            best_move = None
            best_new_max = max_kvpr

            for i, model in enumerate(placement[max_gpu]):
                model_wrr = model.req_rate / model.slo
                # KVPR of max_gpu after removing model
                new_src_mem = mem[max_gpu] + model.model_size
                new_src_wrr = wrr[max_gpu] - model_wrr
                if new_src_wrr > 0:
                    src_kvpr_after = new_src_wrr / new_src_mem
                else:
                    src_kvpr_after = 0.0

                for target in range(gpu_num):
                    if target == max_gpu:
                        continue
                    new_tgt_mem = mem[target] - model.model_size
                    if new_tgt_mem <= 0:
                        continue
                    new_tgt_wrr = wrr[target] + model_wrr
                    tgt_kvpr_after = new_tgt_wrr / new_tgt_mem

                    # New max KVPR after this move
                    new_max = max(src_kvpr_after, tgt_kvpr_after)
                    # Also check all other GPUs
                    for g in range(gpu_num):
                        if g == max_gpu or g == target:
                            continue
                        if mem[g] < GPU_MEM_SIZE:
                            gk = calc_kvpr(wrr[g], mem[g])
                            if gk > new_max:
                                new_max = gk

                    if new_max < best_new_max - 1e-12:
                        best_new_max = new_max
                        best_move = ('move', i, max_gpu, target)

            # Try swapping models between max_gpu and other GPUs
            for i, model_a in enumerate(placement[max_gpu]):
                a_wrr = model_a.req_rate / model_a.slo
                for target in range(gpu_num):
                    if target == max_gpu:
                        continue
                    for j, model_b in enumerate(placement[target]):
                        b_wrr = model_b.req_rate / model_b.slo
                        # Check memory feasibility
                        new_src_mem = mem[max_gpu] + model_a.model_size - model_b.model_size
                        new_tgt_mem = mem[target] + model_b.model_size - model_a.model_size
                        if new_src_mem <= 0 or new_tgt_mem <= 0:
                            continue

                        new_src_wrr = wrr[max_gpu] - a_wrr + b_wrr
                        new_tgt_wrr = wrr[target] - b_wrr + a_wrr

                        src_kvpr_after = new_src_wrr / new_src_mem if new_src_wrr > 0 else 0.0
                        tgt_kvpr_after = new_tgt_wrr / new_tgt_mem if new_tgt_wrr > 0 else 0.0

                        new_max = max(src_kvpr_after, tgt_kvpr_after)
                        for g in range(gpu_num):
                            if g == max_gpu or g == target:
                                continue
                            if mem[g] < GPU_MEM_SIZE:
                                gk = calc_kvpr(wrr[g], mem[g])
                                if gk > new_max:
                                    new_max = gk

                        if new_max < best_new_max - 1e-12:
                            best_new_max = new_max
                            best_move = ('swap', i, max_gpu, j, target)

            if best_move is not None:
                improved = True
                if best_move[0] == 'move':
                    _, idx, src, tgt = best_move
                    model = placement[src][idx]
                    model_wrr = model.req_rate / model.slo
                    placement[src].pop(idx)
                    placement[tgt].append(model)
                    wrr[src] -= model_wrr
                    wrr[tgt] += model_wrr
                    mem[src] += model.model_size
                    mem[tgt] -= model.model_size
                else:  # swap
                    _, idx_a, src, idx_b, tgt = best_move
                    model_a = placement[src][idx_a]
                    model_b = placement[tgt][idx_b]
                    a_wrr = model_a.req_rate / model_a.slo
                    b_wrr = model_b.req_rate / model_b.slo
                    placement[src][idx_a] = model_b
                    placement[tgt][idx_b] = model_a
                    wrr[src] = wrr[src] - a_wrr + b_wrr
                    wrr[tgt] = wrr[tgt] - b_wrr + a_wrr
                    mem[src] = mem[src] + model_a.model_size - model_b.model_size
                    mem[tgt] = mem[tgt] + model_b.model_size - model_a.model_size

        return placement, wrr, mem

    # Try multiple orderings for the greedy phase
    orderings = [
        sorted(models, key=lambda m: m.req_rate / m.slo, reverse=True),
        sorted(models, key=lambda m: m.model_size, reverse=True),
        sorted(models, key=lambda m: (m.req_rate / m.slo) / m.model_size, reverse=True),
        sorted(models, key=lambda m: m.model_size * (m.req_rate / m.slo), reverse=True),
    ]

    best_placement = None
    best_max_kvpr = float('inf')

    for order in orderings:
        try:
            p, w, m = lookahead_greedy(order, gpu_num)
            p, w, m = local_search(p, w, m, gpu_num)
            mk = get_max_kvpr(w, m)
            if mk < best_max_kvpr:
                best_max_kvpr = mk
                best_placement = p
        except ValueError:
            continue

    if best_placement is None:
        raise ValueError("Unable to place all models on GPUs with any ordering.")

    return best_placement

# EVOLVE-BLOCK-END

